-- Converted from docs/du_lieu_daNhap.sql business/history tables.
-- Inserts old repair/replacement/transfer/maintenance records into PhieuThietBi, PhieuThietBiChiTiet and LichSuThietBi.
SET NOCOUNT ON;
IF OBJECT_ID('tempdb..#PhieuCu') IS NOT NULL DROP TABLE #PhieuCu;
CREATE TABLE #PhieuCu (LegacyKey NVARCHAR(50) NOT NULL PRIMARY KEY, SoPhieu NVARCHAR(50) NOT NULL, LoaiPhieu NVARCHAR(50) NOT NULL, MaThietBi NVARCHAR(50) NOT NULL, MaNguoiDung NVARCHAR(50) NULL, TenNguoiDung NVARCHAR(250) NULL, MaPhongBan NVARCHAR(50) NULL, TenPhongBan NVARCHAR(250) NULL, MaBoPhan NVARCHAR(50) NULL, TenBoPhan NVARCHAR(250) NULL, MaNguoiDungTruoc NVARCHAR(50) NULL, TenNguoiDungTruoc NVARCHAR(250) NULL, MaPhongBanTruoc NVARCHAR(50) NULL, TenPhongBanTruoc NVARCHAR(250) NULL, NgayPhieu DATETIME2 NOT NULL, NoiDung NVARCHAR(1000) NULL, ChiPhi DECIMAL(18,2) NULL, FileScan01 NVARCHAR(500) NULL, FileScan02 NVARCHAR(500) NULL, GhiChu NVARCHAR(1000) NULL, LogDate DATETIME2 NULL, LogUser NVARCHAR(50) NULL, LogDateLast DATETIME2 NULL, LogUserLast NVARCHAR(50) NULL);
IF OBJECT_ID('tempdb..#ChiTietCu') IS NOT NULL DROP TABLE #ChiTietCu;
CREATE TABLE #ChiTietCu (LegacyKey NVARCHAR(50) NOT NULL, DetailKey NVARCHAR(50) NOT NULL PRIMARY KEY, MaThongSo NVARCHAR(50) NULL, TenThongSo NVARCHAR(250) NULL, GiaTri NVARCHAR(1000) NULL, DonVi NVARCHAR(250) NULL, GhiChu NVARCHAR(500) NULL, ChiPhi DECIMAL(18,2) NULL, LogDate DATETIME2 NULL, LogUser NVARCHAR(50) NULL);

;WITH Units AS (
    SELECT MaPhongBan AS MaDonVi, TenPhongBan AS TenDonVi FROM #PhieuCu WHERE MaPhongBan IS NOT NULL
    UNION SELECT MaBoPhan, TenBoPhan FROM #PhieuCu WHERE MaBoPhan IS NOT NULL
    UNION SELECT MaPhongBanTruoc, TenPhongBanTruoc FROM #PhieuCu WHERE MaPhongBanTruoc IS NOT NULL
), UnitSource AS (
    SELECT MaDonVi, COALESCE(MAX(NULLIF(TenDonVi, N'')), N'Đơn vị cũ ' + MaDonVi) AS TenDonVi FROM Units GROUP BY MaDonVi
)
MERGE dbo.DonViBoPhan AS target
USING UnitSource AS source
ON target.MaDonVi = source.MaDonVi
WHEN MATCHED THEN UPDATE SET TenDonVi = CASE WHEN target.LoaiDonVi = N'DON_VI_CHA_CU' OR target.TenDonVi LIKE N'Đơn vị cũ %' THEN source.TenDonVi ELSE target.TenDonVi END, IsActive = 1
WHEN NOT MATCHED THEN INSERT (Id, MaDonVi, TenDonVi, LoaiDonVi, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
VALUES (NEWID(), source.MaDonVi, source.TenDonVi, N'PHONG_BAN_CU', 1, SYSDATETIME(), N'MIGRATION', N'Migration');

;WITH Users AS (
    SELECT MaNguoiDung, TenNguoiDung, MaPhongBan FROM #PhieuCu WHERE MaNguoiDung IS NOT NULL
    UNION SELECT MaNguoiDungTruoc, TenNguoiDungTruoc, MaPhongBanTruoc FROM #PhieuCu WHERE MaNguoiDungTruoc IS NOT NULL
), UserSource AS (
    SELECT u.MaNguoiDung, COALESCE(MAX(NULLIF(u.TenNguoiDung, N'')), N'Người sử dụng cũ ' + u.MaNguoiDung) AS TenNguoiDung, MAX(dv.Id) AS DonViBoPhanId
    FROM Users u LEFT JOIN dbo.DonViBoPhan dv ON dv.MaDonVi = u.MaPhongBan GROUP BY u.MaNguoiDung
)
MERGE dbo.NguoiSuDungThietBi AS target
USING UserSource AS source
ON target.MaNguoiDung = source.MaNguoiDung
WHEN MATCHED THEN UPDATE SET TenNguoiDung = source.TenNguoiDung, DonViBoPhanId = COALESCE(target.DonViBoPhanId, source.DonViBoPhanId), IsActive = 1
WHEN NOT MATCHED THEN INSERT (Id, MaNguoiDung, TenNguoiDung, DonViBoPhanId, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap)
VALUES (NEWID(), source.MaNguoiDung, source.TenNguoiDung, source.DonViBoPhanId, 1, SYSDATETIME(), N'MIGRATION', N'Migration');

;WITH PhieuSource AS (
    SELECT p.*, tb.Id AS ThietBiId, pb.Id AS PhongBanId, bp.Id AS BoPhanId, nsd.Id AS NguoiSuDungId
    FROM #PhieuCu p
    JOIN dbo.ThietBi tb ON tb.MaThietBi = p.MaThietBi
    LEFT JOIN dbo.DonViBoPhan pb ON pb.MaDonVi = p.MaPhongBan
    LEFT JOIN dbo.DonViBoPhan bp ON bp.MaDonVi = p.MaBoPhan
    LEFT JOIN dbo.NguoiSuDungThietBi nsd ON nsd.MaNguoiDung = p.MaNguoiDung
)
MERGE dbo.PhieuThietBi AS target
USING PhieuSource AS source
ON target.SoPhieu = source.SoPhieu AND target.LoaiPhieu = source.LoaiPhieu
WHEN MATCHED THEN UPDATE SET
    NgayPhieu = source.NgayPhieu, ThietBiId = source.ThietBiId, PhongBanId = source.PhongBanId, BoPhanId = source.BoPhanId, NguoiSuDungId = source.NguoiSuDungId,
    NoiDung = source.NoiDung, ChiPhi = source.ChiPhi, FileScan01 = source.FileScan01, FileScan02 = source.FileScan02, GhiChu = source.GhiChu, IsActive = 1,
    NgayKhoiTao = COALESCE(source.LogDate, target.NgayKhoiTao), MaNguoiNhap = COALESCE(NULLIF(source.LogUser, N''), target.MaNguoiNhap), TenNguoiNhap = COALESCE(NULLIF(source.LogUser, N''), target.TenNguoiNhap),
    NgayChinhSuaCuoiCung = source.LogDateLast, MaNguoiChinhSua = source.LogUserLast, TenNguoiChinhSua = source.LogUserLast
WHEN NOT MATCHED THEN INSERT (Id, SoPhieu, LoaiPhieu, NgayPhieu, ThietBiId, PhongBanId, BoPhanId, NguoiSuDungId, NoiDung, ChiPhi, FileScan01, FileScan02, GhiChu, IsActive, NgayKhoiTao, MaNguoiNhap, TenNguoiNhap, NgayChinhSuaCuoiCung, MaNguoiChinhSua, TenNguoiChinhSua)
VALUES (NEWID(), source.SoPhieu, source.LoaiPhieu, source.NgayPhieu, source.ThietBiId, source.PhongBanId, source.BoPhanId, source.NguoiSuDungId, source.NoiDung, source.ChiPhi, source.FileScan01, source.FileScan02, source.GhiChu, 1, COALESCE(source.LogDate, SYSDATETIME()), source.LogUser, source.LogUser, source.LogDateLast, source.LogUserLast, source.LogUserLast);

DELETE c
FROM dbo.PhieuThietBiChiTiet c
JOIN dbo.PhieuThietBi p ON p.Id = c.PhieuThietBiId
JOIN #PhieuCu pc ON pc.SoPhieu = p.SoPhieu AND pc.LoaiPhieu = p.LoaiPhieu;

SELECT NEWID(), p.Id, COALESCE(ct.TenThongSo, ct.MaThongSo), ct.GiaTri, ct.ChiPhi, ct.GhiChu, COALESCE(ct.LogDate, pc.LogDate, SYSDATETIME()), COALESCE(ct.LogUser, pc.LogUser), COALESCE(ct.LogUser, pc.LogUser)
FROM #ChiTietCu ct
JOIN #PhieuCu pc ON pc.LegacyKey = ct.LegacyKey
JOIN dbo.PhieuThietBi p ON p.SoPhieu = pc.SoPhieu AND p.LoaiPhieu = pc.LoaiPhieu;

DELETE ls
FROM dbo.LichSuThietBi ls
JOIN dbo.PhieuThietBi p ON p.Id = ls.NghiepVuId
JOIN #PhieuCu pc ON pc.SoPhieu = p.SoPhieu AND pc.LoaiPhieu = p.LoaiPhieu;

;WITH HistorySource AS (
    SELECT pc.*, p.Id AS PhieuId, tb.Id AS ThietBiId, pbSau.Id AS PhongBanSauId, bpSau.Id AS BoPhanSauId, nsdSau.Id AS NguoiSuDungSauId,
        pbTruoc.Id AS PhongBanTruocId, nsdTruoc.Id AS NguoiSuDungTruocId
    FROM #PhieuCu pc
    JOIN dbo.PhieuThietBi p ON p.SoPhieu = pc.SoPhieu AND p.LoaiPhieu = pc.LoaiPhieu
    JOIN dbo.ThietBi tb ON tb.MaThietBi = pc.MaThietBi
    LEFT JOIN dbo.DonViBoPhan pbSau ON pbSau.MaDonVi = pc.MaPhongBan
    LEFT JOIN dbo.DonViBoPhan bpSau ON bpSau.MaDonVi = pc.MaBoPhan
    LEFT JOIN dbo.NguoiSuDungThietBi nsdSau ON nsdSau.MaNguoiDung = pc.MaNguoiDung
    LEFT JOIN dbo.DonViBoPhan pbTruoc ON pbTruoc.MaDonVi = pc.MaPhongBanTruoc
    LEFT JOIN dbo.NguoiSuDungThietBi nsdTruoc ON nsdTruoc.MaNguoiDung = pc.MaNguoiDungTruoc
)
SELECT NEWID(), ThietBiId, LoaiPhieu, PhieuId, PhongBanTruocId, PhongBanSauId, BoPhanSauId, NguoiSuDungTruocId, NguoiSuDungSauId,
    CONCAT(LoaiPhieu, N' từ dữ liệu cũ ', SoPhieu, CASE WHEN NoiDung IS NULL THEN N'' ELSE N': ' + NoiDung END), NgayPhieu, COALESCE(LogDate, SYSDATETIME()), LogUser, LogUser
FROM HistorySource;

DROP TABLE #ChiTietCu;
DROP TABLE #PhieuCu;
GO
